const http = require('http');
const fs = require('fs');
const path = require('path');
const { pipeline } = require('stream');
const { promisify } = require('util');

const pipelineAsync = promisify(pipeline);

function parseMultipartFormData(buffer, boundary) {
  const parts = [];
  const boundaryBuffer = Buffer.from(`--${boundary}`);
  const endBoundaryBuffer = Buffer.from(`--${boundary}--`);
  
  let start = 0;
  let end = 0;
  
  while ((end = buffer.indexOf(boundaryBuffer, start)) !== -1) {
    if (start !== 0) {
      const partData = buffer.slice(start, end);
      const headerEnd = partData.indexOf('\r\n\r\n');
      
      if (headerEnd !== -1) {
        const headers = partData.slice(0, headerEnd).toString();
        const content = partData.slice(headerEnd + 4, partData.length - 2);
        
        const nameMatch = headers.match(/name="([^"]+)"/);
        const filenameMatch = headers.match(/filename="([^"]+)"/);
        const contentTypeMatch = headers.match(/Content-Type: (.+)/);
        
        parts.push({
          name: nameMatch ? nameMatch[1] : null,
          filename: filenameMatch ? filenameMatch[1] : null,
          contentType: contentTypeMatch ? contentTypeMatch[1].trim() : null,
          data: content
        });
      }
    }
    
    start = end + boundaryBuffer.length + 2;
  }
  
  return parts;
}

function handleFileUpload(req, uploadDir = './uploads') {
  return new Promise((resolve, reject) => {
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true });
    }

    const contentType = req.headers['content-type'];
    
    if (!contentType || !contentType.includes('multipart/form-data')) {
      return reject(new Error('Content-Type must be multipart/form-data'));
    }

    const boundaryMatch = contentType.match(/boundary=(.+)$/);
    if (!boundaryMatch) {
      return reject(new Error('No boundary found in Content-Type'));
    }

    const boundary = boundaryMatch[1];
    const chunks = [];

    req.on('data', (chunk) => {
      chunks.push(chunk);
    });

    req.on('end', () => {
      try {
        const buffer = Buffer.concat(chunks);
        const parts = parseMultipartFormData(buffer, boundary);
        const uploadedFiles = [];

        parts.forEach((part) => {
          if (part.filename) {
            const sanitizedFilename = path.basename(part.filename);
            const timestamp = Date.now();
            const uniqueFilename = `${timestamp}_${sanitizedFilename}`;
            const filepath = path.join(uploadDir, uniqueFilename);

            fs.writeFileSync(filepath, part.data);

            uploadedFiles.push({
              fieldName: part.name,
              originalName: sanitizedFilename,
              savedName: uniqueFilename,
              path: filepath,
              size: part.data.length,
              contentType: part.contentType
            });
          }
        });

        resolve(uploadedFiles);
      } catch (error) {
        reject(error);
      }
    });

    req.on('error', (error) => {
      reject(error);
    });
  });
}

function createUploadServer(port = 3000, uploadDir = './uploads') {
  const server = http.createServer(async (req, res) => {
    res.setHeader('Access-Control-Allow-Origin', '*');
    res.setHeader('Access-Control-Allow-Methods', 'POST, OPTIONS');
    res.setHeader('Access-Control-Allow-Headers', 'Content-Type');

    if (req.method === 'OPTIONS') {
      res.writeHead(204);
      res.end();
      return;
    }

    if (req.method === 'POST' && req.url === '/upload') {
      try {
        const uploadedFiles = await handleFileUpload(req, uploadDir);
        
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          success: true,
          message: 'Files uploaded successfully',
          files: uploadedFiles
        }));
      } catch (error) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          success: false,
          message: error.message
        }));
      }
    } else {
      res.writeHead(404, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        success: false,
        message: 'Not Found'
      }));
    }
  });

  server.listen(port, () => {
    console.log(`Upload server running on http://localhost:${port}`);
  });

  return server;
}

module.exports = {
  handleFileUpload,
  createUploadServer
};